import{_ as a,I as n,c as r,o as i,a5 as e,J as c,j as d}from"./chunks/framework.Dtwt352Q.js";const u=JSON.parse('{"title":"OpenCode Zen","description":"OpenCode 团队精选的模型服务","frontmatter":{"title":"OpenCode Zen","description":"OpenCode 团队精选的模型服务"},"headers":[],"relativePath":"appendix/zen.md","filePath":"appendix/zen.md","lastUpdated":1772014034000}'),p={name:"appendix/zen.md"};function s(l,t,h,k,g,$){const o=n("AdInArticle");return i(),r("div",null,[t[0]||(t[0]=e('<h1 id="opencode-zen" tabindex="-1">OpenCode Zen <a class="header-anchor" href="#opencode-zen" aria-label="Permalink to “OpenCode Zen”">​</a></h1><p>OpenCode Zen 是由 OpenCode 团队测试和验证的精选模型服务。</p><blockquote><p>OpenCode Zen 目前处于 Beta 阶段。</p></blockquote><p>Zen 像 OpenCode 中的其他提供商一样工作。你登录 OpenCode Zen 获取 API 密钥。它是<strong>完全可选的</strong>，不使用它也可以正常使用 OpenCode。</p><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to “背景”">​</a></h2><p>市面上有大量模型，但只有少数能作为编程代理良好工作。此外，大多数提供商配置差异很大，导致性能和质量参差不齐。</p><blockquote><p>我们测试了一组与 OpenCode 配合良好的模型和提供商。</p></blockquote><p>如果你通过 OpenRouter 等服务使用模型，无法确定是否获得了最佳版本。</p><p>为此，我们做了几件事：</p><ol><li>测试了一组精选模型，并与团队讨论如何最佳运行</li><li>与几家提供商合作，确保正确提供服务</li><li>对模型/提供商组合进行基准测试，得出推荐列表</li></ol><p>OpenCode Zen 是一个 AI 网关，让你可以访问这些模型。</p><h2 id="使用方法" tabindex="-1">使用方法 <a class="header-anchor" href="#使用方法" aria-label="Permalink to “使用方法”">​</a></h2>',12)),c(o),t[1]||(t[1]=e('<p>OpenCode Zen 像其他提供商一样工作：</p><ol><li>登录 <a href="https://console.opencode.ai" target="_blank" rel="noreferrer">OpenCode Zen 控制台</a>，添加付款信息，复制 API 密钥</li><li>在 TUI 中运行 <code>/connect</code> 命令，选择 OpenCode Zen，粘贴 API 密钥</li><li>在 TUI 中运行 <code>/models</code> 查看推荐模型列表</li></ol><p>按请求计费，可向账户添加额度。</p><h2 id="api-端点" tabindex="-1">API 端点 <a class="header-anchor" href="#api-端点" aria-label="Permalink to “API 端点”">​</a></h2><p>也可以通过以下 API 端点访问模型：</p><table tabindex="0"><thead><tr><th>模型</th><th>模型 ID</th><th>端点</th><th>AI SDK 包</th></tr></thead><tbody><tr><td>GPT 5.2</td><td>gpt-5.2</td><td><code>https://opencode.ai/zen/v1/responses</code></td><td><code>@ai-sdk/openai</code></td></tr><tr><td>GPT 5.1</td><td>gpt-5.1</td><td><code>https://opencode.ai/zen/v1/responses</code></td><td><code>@ai-sdk/openai</code></td></tr><tr><td>GPT 5.1 Codex</td><td>gpt-5.1-codex</td><td><code>https://opencode.ai/zen/v1/responses</code></td><td><code>@ai-sdk/openai</code></td></tr><tr><td>GPT 5.1 Codex Max</td><td>gpt-5.1-codex-max</td><td><code>https://opencode.ai/zen/v1/responses</code></td><td><code>@ai-sdk/openai</code></td></tr><tr><td>GPT 5.1 Codex Mini</td><td>gpt-5.1-codex-mini</td><td><code>https://opencode.ai/zen/v1/responses</code></td><td><code>@ai-sdk/openai</code></td></tr><tr><td>GPT 5</td><td>gpt-5</td><td><code>https://opencode.ai/zen/v1/responses</code></td><td><code>@ai-sdk/openai</code></td></tr><tr><td>GPT 5 Codex</td><td>gpt-5-codex</td><td><code>https://opencode.ai/zen/v1/responses</code></td><td><code>@ai-sdk/openai</code></td></tr><tr><td>GPT 5 Nano</td><td>gpt-5-nano</td><td><code>https://opencode.ai/zen/v1/responses</code></td><td><code>@ai-sdk/openai</code></td></tr><tr><td>Claude Sonnet 4.5</td><td>claude-sonnet-4-5</td><td><code>https://opencode.ai/zen/v1/messages</code></td><td><code>@ai-sdk/anthropic</code></td></tr><tr><td>Claude Sonnet 4</td><td>claude-sonnet-4</td><td><code>https://opencode.ai/zen/v1/messages</code></td><td><code>@ai-sdk/anthropic</code></td></tr><tr><td>Claude Haiku 4.5</td><td>claude-haiku-4-5</td><td><code>https://opencode.ai/zen/v1/messages</code></td><td><code>@ai-sdk/anthropic</code></td></tr><tr><td>Claude Haiku 3.5</td><td>claude-3-5-haiku</td><td><code>https://opencode.ai/zen/v1/messages</code></td><td><code>@ai-sdk/anthropic</code></td></tr><tr><td>Claude Opus 4.5</td><td>claude-opus-4-5</td><td><code>https://opencode.ai/zen/v1/messages</code></td><td><code>@ai-sdk/anthropic</code></td></tr><tr><td>Claude Opus 4.1</td><td>claude-opus-4-1</td><td><code>https://opencode.ai/zen/v1/messages</code></td><td><code>@ai-sdk/anthropic</code></td></tr><tr><td>MiniMax M2.1</td><td>minimax-m2.1-free</td><td><code>https://opencode.ai/zen/v1/messages</code></td><td><code>@ai-sdk/anthropic</code></td></tr><tr><td>Gemini 3 Pro</td><td>gemini-3-pro</td><td><code>https://opencode.ai/zen/v1/models/gemini-3-pro</code></td><td><code>@ai-sdk/google</code></td></tr><tr><td>Gemini 3 Flash</td><td>gemini-3-flash</td><td><code>https://opencode.ai/zen/v1/models/gemini-3-flash</code></td><td><code>@ai-sdk/google</code></td></tr><tr><td>GLM 4.6</td><td>glm-4.6</td><td><code>https://opencode.ai/zen/v1/chat/completions</code></td><td><code>@ai-sdk/openai-compatible</code></td></tr><tr><td>GLM 4.7</td><td>glm-4.7-free</td><td><code>https://opencode.ai/zen/v1/chat/completions</code></td><td><code>@ai-sdk/openai-compatible</code></td></tr><tr><td>Kimi K2</td><td>kimi-k2</td><td><code>https://opencode.ai/zen/v1/chat/completions</code></td><td><code>@ai-sdk/openai-compatible</code></td></tr><tr><td>Kimi K2 Thinking</td><td>kimi-k2-thinking</td><td><code>https://opencode.ai/zen/v1/chat/completions</code></td><td><code>@ai-sdk/openai-compatible</code></td></tr><tr><td>Qwen3 Coder 480B</td><td>qwen3-coder</td><td><code>https://opencode.ai/zen/v1/chat/completions</code></td><td><code>@ai-sdk/openai-compatible</code></td></tr><tr><td>Grok Code Fast 1</td><td>grok-code</td><td><code>https://opencode.ai/zen/v1/chat/completions</code></td><td><code>@ai-sdk/openai-compatible</code></td></tr><tr><td>Big Pickle</td><td>big-pickle</td><td><code>https://opencode.ai/zen/v1/chat/completions</code></td><td><code>@ai-sdk/openai-compatible</code></td></tr></tbody></table><p>OpenCode 配置中的模型 ID 使用格式 <code>opencode/&lt;model-id&gt;</code>。例如 GPT 5.1 Codex 使用 <code>opencode/gpt-5.1-codex</code>。</p><h3 id="获取模型列表" tabindex="-1">获取模型列表 <a class="header-anchor" href="#获取模型列表" aria-label="Permalink to “获取模型列表”">​</a></h3><p>获取可用模型及其元数据：</p>',9)),t[2]||(t[2]=d("div",{class:"language-"},[d("button",{title:"Copy Code",class:"copy"}),d("span",{class:"lang"}),d("pre",null,[d("code",{"v-pre":""},"https://opencode.ai/zen/v1/models")])],-1)),t[3]||(t[3]=e('<h2 id="定价" tabindex="-1">定价 <a class="header-anchor" href="#定价" aria-label="Permalink to “定价”">​</a></h2><p>按请求付费。以下是<strong>每 100 万 token</strong> 的价格：</p><table tabindex="0"><thead><tr><th>模型</th><th>输入</th><th>输出</th><th>缓存读取</th><th>缓存写入</th></tr></thead><tbody><tr><td>Big Pickle</td><td>免费</td><td>免费</td><td>免费</td><td>-</td></tr><tr><td>Grok Code Fast 1</td><td>免费</td><td>免费</td><td>免费</td><td>-</td></tr><tr><td>MiniMax M2.1</td><td>免费</td><td>免费</td><td>免费</td><td>-</td></tr><tr><td>GLM 4.7</td><td>免费</td><td>免费</td><td>免费</td><td>-</td></tr><tr><td>GLM 4.6</td><td>$0.60</td><td>$2.20</td><td>$0.10</td><td>-</td></tr><tr><td>Kimi K2</td><td>$0.40</td><td>$2.50</td><td>-</td><td>-</td></tr><tr><td>Kimi K2 Thinking</td><td>$0.40</td><td>$2.50</td><td>-</td><td>-</td></tr><tr><td>Qwen3 Coder 480B</td><td>$0.45</td><td>$1.50</td><td>-</td><td>-</td></tr><tr><td>Claude Sonnet 4.5 (≤ 200K tokens)</td><td>$3.00</td><td>$15.00</td><td>$0.30</td><td>$3.75</td></tr><tr><td>Claude Sonnet 4.5 (&gt; 200K tokens)</td><td>$6.00</td><td>$22.50</td><td>$0.60</td><td>$7.50</td></tr><tr><td>Claude Sonnet 4 (≤ 200K tokens)</td><td>$3.00</td><td>$15.00</td><td>$0.30</td><td>$3.75</td></tr><tr><td>Claude Sonnet 4 (&gt; 200K tokens)</td><td>$6.00</td><td>$22.50</td><td>$0.60</td><td>$7.50</td></tr><tr><td>Claude Haiku 4.5</td><td>$1.00</td><td>$5.00</td><td>$0.10</td><td>$1.25</td></tr><tr><td>Claude Haiku 3.5</td><td>$0.80</td><td>$4.00</td><td>$0.08</td><td>$1.00</td></tr><tr><td>Claude Opus 4.5</td><td>$5.00</td><td>$25.00</td><td>$0.50</td><td>$6.25</td></tr><tr><td>Claude Opus 4.1</td><td>$15.00</td><td>$75.00</td><td>$1.50</td><td>$18.75</td></tr><tr><td>Gemini 3 Pro (≤ 200K tokens)</td><td>$2.00</td><td>$12.00</td><td>$0.20</td><td>-</td></tr><tr><td>Gemini 3 Pro (&gt; 200K tokens)</td><td>$4.00</td><td>$18.00</td><td>$0.40</td><td>-</td></tr><tr><td>Gemini 3 Flash</td><td>$0.50</td><td>$3.00</td><td>$0.05</td><td>-</td></tr><tr><td>GPT 5.2</td><td>$1.75</td><td>$14.00</td><td>$0.175</td><td>-</td></tr><tr><td>GPT 5.1</td><td>$1.07</td><td>$8.50</td><td>$0.107</td><td>-</td></tr><tr><td>GPT 5.1 Codex</td><td>$1.07</td><td>$8.50</td><td>$0.107</td><td>-</td></tr><tr><td>GPT 5.1 Codex Max</td><td>$1.25</td><td>$10.00</td><td>$0.125</td><td>-</td></tr><tr><td>GPT 5.1 Codex Mini</td><td>$0.25</td><td>$2.00</td><td>$0.025</td><td>-</td></tr><tr><td>GPT 5</td><td>$1.07</td><td>$8.50</td><td>$0.107</td><td>-</td></tr><tr><td>GPT 5 Codex</td><td>$1.07</td><td>$8.50</td><td>$0.107</td><td>-</td></tr><tr><td>GPT 5 Nano</td><td>免费</td><td>免费</td><td>免费</td><td>-</td></tr></tbody></table><p>使用历史中可能看到 <em>Claude Haiku 3.5</em>，这是用于生成会话标题的低成本模型。</p><blockquote><p>信用卡费用按成本传递（每笔 4.4% + $0.30），我们不收取额外费用。</p></blockquote><p>免费模型说明：</p><ul><li><strong>Grok Code Fast 1</strong>：限时免费，xAI 团队正在收集反馈以改进 Grok Code</li><li><strong>GLM 4.7</strong>：限时免费，团队正在收集反馈以改进模型</li><li><strong>MiniMax M2.1</strong>：限时免费，团队正在收集反馈以改进模型</li><li><strong>Big Pickle</strong>：隐身模型，限时免费，团队正在收集反馈以改进模型</li></ul><h3 id="自动充值" tabindex="-1">自动充值 <a class="header-anchor" href="#自动充值" aria-label="Permalink to “自动充值”">​</a></h3><p>余额低于 $5 时，Zen 会自动充值 $20。</p><p>可以更改自动充值金额，也可以完全禁用自动充值。</p><h3 id="月度限额" tabindex="-1">月度限额 <a class="header-anchor" href="#月度限额" aria-label="Permalink to “月度限额”">​</a></h3><p>可以为整个工作区和每个团队成员设置月度使用限额。</p><p>例如，设置月度限额为 $20，Zen 每月不会使用超过 $20。但如果启用了自动充值，余额低于 $5 时可能会充值超过 $20。</p><h2 id="隐私" tabindex="-1">隐私 <a class="header-anchor" href="#隐私" aria-label="Permalink to “隐私”">​</a></h2><p>所有模型托管在美国。提供商遵循零保留策略，不使用你的数据进行模型训练，但有以下例外：</p><ul><li><strong>Grok Code Fast 1</strong>：免费期间收集的数据可能用于改进 Grok Code</li><li><strong>GLM 4.7</strong>：免费期间收集的数据可能用于改进模型</li><li><strong>MiniMax M2.1</strong>：免费期间收集的数据可能用于改进模型</li><li><strong>Big Pickle</strong>：免费期间收集的数据可能用于改进模型</li><li><strong>OpenAI API</strong>：请求根据 <a href="https://platform.openai.com/docs/guides/your-data" target="_blank" rel="noreferrer">OpenAI 数据政策</a> 保留 30 天</li><li><strong>Anthropic API</strong>：请求根据 <a href="https://docs.anthropic.com/en/docs/claude-code/data-usage" target="_blank" rel="noreferrer">Anthropic 数据政策</a> 保留 30 天</li></ul><h2 id="团队功能" tabindex="-1">团队功能 <a class="header-anchor" href="#团队功能" aria-label="Permalink to “团队功能”">​</a></h2><p>Zen 非常适合团队使用。可以邀请队友、分配角色、管理团队使用的模型等。</p><blockquote><p>Beta 期间工作区管理免费。</p></blockquote><h3 id="角色" tabindex="-1">角色 <a class="header-anchor" href="#角色" aria-label="Permalink to “角色”">​</a></h3><p>可以邀请队友并分配角色：</p><ul><li><strong>Admin</strong>：管理模型、成员、API 密钥和账单</li><li><strong>Member</strong>：只能管理自己的 API 密钥</li></ul><p>管理员还可以为每个成员设置月度消费限额。</p><h3 id="模型访问控制" tabindex="-1">模型访问控制 <a class="header-anchor" href="#模型访问控制" aria-label="Permalink to “模型访问控制”">​</a></h3><p>管理员可以为工作区启用或禁用特定模型。向禁用模型发送的请求会返回错误。</p><p>这适用于禁止使用收集数据的模型。</p><h3 id="自带密钥" tabindex="-1">自带密钥 <a class="header-anchor" href="#自带密钥" aria-label="Permalink to “自带密钥”">​</a></h3><p>可以使用自己的 OpenAI 或 Anthropic API 密钥，同时访问 Zen 中的其他模型。</p><p>使用自己的密钥时，token 直接由提供商计费，而非 Zen。</p><p>例如，你的组织可能已有 OpenAI 或 Anthropic 密钥，想使用它而非 Zen 提供的密钥。</p><h2 id="目标" tabindex="-1">目标 <a class="header-anchor" href="#目标" aria-label="Permalink to “目标”">​</a></h2><p>我们创建 OpenCode Zen 是为了：</p><ol><li><strong>基准测试</strong>编程代理的最佳模型/提供商</li><li>访问<strong>最高质量</strong>选项，不降级性能或路由到更便宜的提供商</li><li>按成本<strong>传递价格下降</strong>，唯一加价是处理费用</li><li><strong>无锁定</strong>，允许与任何其他编程代理一起使用，也允许在 OpenCode 中使用任何其他提供商</li></ol>',33))])}const C=a(p,[["render",s]]);export{u as __pageData,C as default};
